DELIMITER $$
--
-- Eventos
--
DROP EVENT IF EXISTS `dec_hours`$$
CREATE DEFINER=`root`@`localhost` EVENT `dec_hours` ON SCHEDULE EVERY 1 SECOND STARTS '2025-07-15 22:40:57' ON COMPLETION NOT PRESERVE ENABLE DO BEGIN
        DECLARE v INTEGER;
        DECLARE CONTINUE HANDLER FOR SQLEXCEPTION BEGIN END;

        SET v = 1;
        UPDATE info SET fx_loterry_time = fx_loterry_time - v;
          
    END$$

DROP EVENT IF EXISTS `session_update`$$
CREATE DEFINER=`root`@`localhost` EVENT `session_update` ON SCHEDULE EVERY 43200 SECOND STARTS '2025-07-15 23:19:24' ON COMPLETION NOT PRESERVE ENABLE COMMENT 'Reset fx time cicle' DO BEGIN

UPDATE info SET lt_session = lt_session + 1;
      END$$

DROP EVENT IF EXISTS `fx_reset_time`$$
CREATE DEFINER=`root`@`localhost` EVENT `fx_reset_time` ON SCHEDULE EVERY 1 SECOND STARTS '2025-07-15 23:49:33' ON COMPLETION NOT PRESERVE ENABLE DO BEGIN
        DECLARE CONTINUE HANDLER FOR SQLEXCEPTION BEGIN END;

      UPDATE info SET fx_loterry_time = IF(fx_loterry_time < 1 , 43200 , fx_loterry_time);
    END$$

DROP EVENT IF EXISTS `dec_time_dep_with_pending`$$
CREATE DEFINER=`root`@`localhost` EVENT `dec_time_dep_with_pending` ON SCHEDULE EVERY 1 SECOND STARTS '2025-07-23 20:24:21' ON COMPLETION NOT PRESERVE ENABLE COMMENT 'dec deposit/with pending time' DO BEGIN
        DECLARE CONTINUE HANDLER FOR SQLEXCEPTION BEGIN END;
        
      UPDATE rel_deposits SET hms = IF(hms > 1 , hms-1 , 0);
      UPDATE saque SET hms = IF(hms > 1 , hms-1 , 0);
    END$$

DELIMITER ;
